import { PeAuthType, OpenAMOptions } from '../declarations/index';
import { HttpClient, HttpParams } from '@angular/common/http';
import { PeAuthFlow } from './flows/pe-auth-flow';
import { AuthorizationCodeFlow } from './flows/authorization-code.flow';
import { ImplicitFlow } from './flows/implicit.flow';
import { formatCookieName } from './utils/cookie';
import { AuthorizationCodeWithPKCEFlow } from './flows/authorization-code-PKCE.flow';
import * as CryptoJS from 'crypto-js';

export class OpenAMType implements PeAuthType {

    private http: HttpClient;
    
    static readonly FLOW_AUTHORIZATION_CODE = "authorizationCodeFlow";
    static readonly FLOW_IMPLICIT = "implicitFlow";
    static readonly FLOW_AUTHORIZATION_CODE_WITH_PKCE = "authorizationCodeWithPKCEFlow";
    
    ready: Promise<OpenAMType>;
    
    cxnUrl: string;

    autoReload = false;

    cookieName = 'userBadge';
    private static readonly COOKIE_SUFFIXE: any = {
        agent: 'A',
        individu: 'I',
        employeur: 'E',
        partenaire: 'P'
    };

    private _options: OpenAMOptions;
    private _redirect_uri: string;
    private _state: string;
    private _nonce: string;
    private _verifier: string;
    private _code_challenge: string;
    private _code_challenge_method: string;
    
    private storage = localStorage;
    private _storageKey: string;

    private _flow: PeAuthFlow;

    constructor(openAMOptions: OpenAMOptions, mode:string, redirect: string, http: HttpClient) {
      this.cookieName = formatCookieName(this.cookieName, openAMOptions.cadre, OpenAMType.COOKIE_SUFFIXE[mode]);  
      this._options = openAMOptions;
      this._redirect_uri = redirect;
      this._state = this.randomizeString(16);
      this._nonce = this.randomizeString(16);
      this.cxnUrl = this.buildCxnUrl(mode);
      this._storageKey = '__' + openAMOptions.clientId;
      this.http = http;

      switch (this._options.accessTokenFlow) {
          
        case OpenAMType.FLOW_AUTHORIZATION_CODE:
          this._flow = new AuthorizationCodeFlow(http, this._options, this._state, redirect);
          break;
    
        case OpenAMType.FLOW_AUTHORIZATION_CODE_WITH_PKCE:
          this._verifier = this.randomizeString(50);
          this._code_challenge_method = "S256";
          this._code_challenge = this.base64URLEncode(CryptoJS.SHA256(this._verifier));
          this.cxnUrl += `&code_challenge=${this._code_challenge}&code_challenge_method=${this._code_challenge_method}`;
          this._flow = new AuthorizationCodeWithPKCEFlow(http, this._options, this._state, redirect, this._verifier);
          break;

        case OpenAMType.FLOW_IMPLICIT:
          this._flow = new ImplicitFlow()
          break

        default:
          throw 'Access token flow "' + this._options.accessTokenFlow + '" does not exists.';
      }
      this.ready = Promise.resolve(this);
    }

    getTokenFromCookie(cookie: any) {
        return typeof cookie === 'string' ? JSON.parse(cookie) : cookie;
    };
    
    getTokenFromUrl(url: any, callback: (token:any) => void) {
        this._flow.getTokenFromUrl(url, callback);
    };
    
    isValidToken(token:any, time: number) {
        let nonce;
        let state;
        if (time > 0) {
            nonce = this._nonce;
            state = this._state;
            this.storage.setItem(this._storageKey, JSON.stringify({state: this._state, nonce : this._nonce, time: time}));
        } else {
            const lastCxn= JSON.parse(this.storage.getItem(this._storageKey));
            time = lastCxn.time;
            nonce = lastCxn.nonce;
            state = lastCxn.state;
        };
        return this._flow.isValidToken(token, time, state, nonce);
    };

    buildAuthorization(token: any, mode: string) {
        return 'Bearer ' + token['access_token'];
    }

    logout(token: any, callback: ()=>void) {
        if (token !== null) {
            const logoutUrl = this.buildLogoutUrl();
            const oidcParams = new HttpParams().set('id_token_hint', token['id_token']);
            this.http.get(logoutUrl.oidc, { params: oidcParams }).subscribe(callback, err => {
                this.http.get(logoutUrl.oam).subscribe(callback, callback); 
            });
        } else {
            callback();
        }
    }

    private base64URLEncode(words: CryptoJS.lib.WordArray) {
      return CryptoJS.enc.Base64.stringify(words).replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '');
    }

    private buildCxnUrl(mode:string) {
        let url = this._options.openAMUrl + this._options.authorizeResource.url;
        url += (url.indexOf('?') > -1 ? '&' : '?') + 'realm=' + encodeURIComponent('/' + mode);
        url += '&response_type=' + encodeURIComponent(this._options.authorizeResource.responseType);
        url += '&client_id=' + this._options.clientId;
        url += '&scope=' + encodeURIComponent(this._options.authorizeResource.scope);
        url += '&redirect_uri=' + encodeURIComponent(this._redirect_uri);
        url += '&state=' + this._state;
        url += '&nonce=' + this._nonce;
        return url;
    }
    
    private randomizeString(length: number): string {
      return this.base64URLEncode(CryptoJS.lib.WordArray.random(length));
    }
    
    private buildLogoutUrl() {
        let oidc = this._options.openAMUrl + this._options.logoutResource.urlOIDC;
        let oam = this._options.openAMUrl + this._options.logoutResource.urlOpenAM;
        return {
            oidc: oidc,
            oam : oam
        };
    }
}
