import { PeAuthType, NetEntrepriseOptions } from '../declarations/index';
import { searchParams } from '../utils/utils';
import { formatCookieName } from './utils/cookie';

export class NetEntrepriseType implements PeAuthType {

    ready: Promise<NetEntrepriseType>;
    
    cxnUrl: string;

    autoReload = false;

    cookieName = "netToken"
    
    private _options: NetEntrepriseOptions;
    
    constructor(netEntrepriseOptions: NetEntrepriseOptions, mode: string, redirect: string) {
      this.cookieName = formatCookieName(this.cookieName, netEntrepriseOptions.cadre, "");
      this._options = netEntrepriseOptions;
      this.cxnUrl = this.buildCxnUrl(redirect);
      this.ready = Promise.resolve(this);
    }

    getTokenFromCookie(cookie: any) {
        return cookie;
    };
    
    getTokenFromUrl(url: any, callback: (token:any) => void) {
        let token;
        try {
            token = searchParams(url)['ticket'];
        } catch (e) {
            token = null;
        }
        callback(token ? token : null);
    };
    
    isValidToken(token:any, time: number) {
        return token !== null;
    };

    buildAuthorization(token: any, mode: string) {
        return 'Bearer ' + mode + token;
    }

    logout(token: any, callback: () => void) {
        callback();
    }

    private buildCxnUrl(redirect: string): string {
        let url = null;
        if (this._options.netEntrepriseUrl) {
            throw 'Net-Entreprise connexion is not yet implemented.';
        }
        return url;
    }
}