import { PeAuthFlow } from "./pe-auth-flow";
import { searchParams } from '../../utils/utils';

export class ImplicitFlow implements PeAuthFlow {

    getTokenFromUrl(url: any, callback: (token:any) => void) {
        callback(this.extractToken(url.indexOf('#') >= 0 ? url.split('#')[1] : ''));
    }
    
    isValidToken(token:any, time: number, state: string, nonce: string) {
        return token['state'] === state && parseInt(token['expires_in']) * 1000 + time > Date.now();
    };

    private extractToken(url: string) {
        return searchParams(url, {
            scope: true,
            nonce: true,
            expires_in: true,
            token_type: true,
            refresh_token: true,
            id_token: true,
            access_token: true,
            state: true
        });
    }
}